(function() {
var CK = ctx.CanvasKit;
var canvas = ctx.getCanvas();
var W = 390;
var H = 844;
var p = ctx.currentFrame / ctx.sceneFrames;

var bgP = new CK.Paint();
bgP.setStyle(CK.PaintStyle.Fill);
bgP.setAntiAlias(true);

for (var i = 0; i < 8; i++) {
  var t = i / 7;
  bgP.setColor(CK.Color(Math.round(120 + t * 75), Math.round(185 + t * 40), Math.round(235 + t * 15), 1));
  canvas.drawRect(CK.XYWHRect(0, i * H / 8, W, H / 8 + 1), bgP);
}

bgP.setColor(CK.Color(255, 245, 200, 0.12));
canvas.drawCircle(310, 120, 90, bgP);
bgP.setColor(CK.Color(255, 240, 180, 0.45));
canvas.drawCircle(310, 120, 40, bgP);

bgP.setColor(CK.Color(110, 90, 60, 1));
canvas.drawRect(CK.XYWHRect(0, H - 40, W, 40), bgP);
bgP.setColor(CK.Color(90, 150, 60, 1));
canvas.drawRect(CK.XYWHRect(0, H - 40, W, 8), bgP);
bgP.delete();

var _s = 42;
function R() { _s = (_s * 16807) % 2147483647; return (_s - 1) / 2147483646; }
function ease(t) { return t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t; }

var segs = [];
var lvs = [];

function br(x1, y1, a, l, d) {
  if (d > 7 || l < 3) return;
  var x2 = x1 + Math.sin(a) * l;
  var y2 = y1 - Math.cos(a) * l;
  segs.push({
    x1:x1, y1:y1, x2:x2, y2:y2,
    w: Math.max(1.5, (8 - d) * 1.8),
    cr: Math.min(255, 101 + d * 13),
    cg: Math.min(255, 67 + d * 11),
    cb: Math.min(255, 33 + d * 9),
    st: d * 0.08,
    en: Math.min(1, d * 0.08 + 0.12)
  });
  if (d >= 5) {
    var lc = 2 + Math.floor(R() * 2);
    for (var li = 0; li < lc; li++) {
      lvs.push({
        x: x2 + (R() - 0.5) * 16,
        y: y2 + (R() - 0.5) * 16,
        r: 3 + R() * 5,
        cr: 50 + Math.floor(R() * 40),
        cg: 140 + Math.floor(R() * 70),
        cb: 30 + Math.floor(R() * 25),
        st: 0.78 + R() * 0.18
      });
    }
  }
  var aL = 0.25 + R() * 0.35;
  var aR = 0.25 + R() * 0.35;
  var sL = 0.62 + R() * 0.13;
  var sR = 0.62 + R() * 0.13;
  br(x2, y2, a - aL, l * sL, d + 1);
  br(x2, y2, a + aR, l * sR, d + 1);
  if (d > 0 && d < 5 && R() > 0.65) {
    br(x2, y2, a + (R() - 0.5) * 0.4, l * sL * 0.7, d + 1);
  }
}

br(W / 2, H - 40, 0, 170, 0);

var bp = new CK.Paint();
bp.setStyle(CK.PaintStyle.Stroke);
bp.setStrokeCap(CK.StrokeCap.Round);
bp.setAntiAlias(true);

for (var i = 0; i < segs.length; i++) {
  var s = segs[i];
  if (p < s.st) continue;
  var t = ease(Math.min(1, (p - s.st) / (s.en - s.st)));
  bp.setColor(CK.Color(s.cr, s.cg, s.cb, 1));
  bp.setStrokeWidth(s.w);
  canvas.drawLine(s.x1, s.y1, s.x1 + (s.x2 - s.x1) * t, s.y1 + (s.y2 - s.y1) * t, bp);
}
bp.delete();

var lp = new CK.Paint();
lp.setStyle(CK.PaintStyle.Fill);
lp.setAntiAlias(true);

for (var j = 0; j < lvs.length; j++) {
  var lv = lvs[j];
  if (p < lv.st) continue;
  var lt = ease(Math.min(1, (p - lv.st) / 0.15));
  lp.setColor(CK.Color(lv.cr, lv.cg, lv.cb, lt * 0.8));
  canvas.drawCircle(lv.x, lv.y, lv.r * lt, lp);
}
lp.delete();
})();
